	showCustomBadge?: boolean;
	showStartsAt?: boolean;
	icon?: React.ReactNode;
};

// ── Tab categories with their plans ──────────────────────────────────
type TabCategory = {
	label: string;
	value: string;
	plans: PricingPlan[];
};

const tabCategories: TabCategory[] = [
	{
