	className?: string;
}) {
	const external = link.href.startsWith("http");

	return (
		<Link
			className={className}
			href={link.href as Route}
			rel={external ? "noreferrer" : undefined}
			target={external ? "_blank" : undefined}
		>
			{link.label}
		</Link>
	);
}

function FooterLinkList({ links }: { links: Footer01Link[] }) {
	return (
		<ul className="flex flex-col gap-3.5">
			{links.map((link) => (
				<li key={`${link.label}-${link.href}`}>
					<FooterLink
						className="block py-0.5 font-medium text-muted-foreground text-sm transition-colors duration-150 ease-[cubic-bezier(0.23,1,0.32,1)] hover:text-foreground"
						link={link}
					/>
				</li>
			))}
		</ul>
	);
}

function FooterLinkColumn({ group }: { group: Footer01LinkGroup }) {
	return (
		<nav aria-label={group.title} className="flex flex-col gap-4 pl-6">
			<p className="font-medium text-muted-foreground text-xs uppercase tracking-wide">
				{group.title}
			</p>
			<FooterLinkList links={group.links} />
		</nav>
	);
}

function NewsletterForm({
	placeholder,
	buttonText,
	action,
}: {
	placeholder: string;
	buttonText: string;
	action?: string;
}) {
	const inputId = useId();

	function handleSubmit(event: FormEvent<HTMLFormElement>) {
		if (!action) event.preventDefault();
	}

	return (
		<form
			action={action}
			className="w-full max-w-md"
			method={action ? "post" : undefined}
			onSubmit={handleSubmit}
		>
			<label className="sr-only" htmlFor={inputId}>
				Email address
			</label>
			<InputGroup className="h-12">
				<InputGroupInput
					autoComplete="email"
					className="h-full px-4"
					id={inputId}
					name="email"
					placeholder={placeholder}
					required
					spellCheck={false}
					type="email"
				/>
				<InputGroupAddon align="inline-end">
					<InputGroupButton
						className="min-w-28 touch-manipulation transition-transform duration-160 ease-[cubic-bezier(0.23,1,0.32,1)] active:translate-y-0 active:scale-[0.98]"
						size="sm"
						type="submit"
						variant="default"
					>
						{buttonText}
						<ArrowRightIcon aria-hidden="true" data-icon="inline-end" />
					</InputGroupButton>
				</InputGroupAddon>
			</InputGroup>
		</form>
	);
}

function ThemeToggle() {
	const { resolvedTheme, setTheme } = useTheme();

	return (
		<Button
			aria-label="Toggle theme"
			className="relative touch-manipulation transition-transform duration-160 ease-[cubic-bezier(0.23,1,0.32,1)] active:scale-[0.97]"
			onClick={() => setTheme(resolvedTheme === "dark" ? "light" : "dark")}
			size="icon-sm"
			type="button"
			variant="ghost"
		>
			<SunIcon
				aria-hidden="true"
				className="dark:hidden"
				data-icon="inline-start"
			/>
			<MoonIcon
				aria-hidden="true"
				className="hidden dark:block"
				data-icon="inline-start"
			/>
		</Button>
	);
}

function Wordmark({
	logo,
	brandName,
	brandHref,
}: {
	logo?: ReactNode;
	brandName: string;
	brandHref: string;
}) {
	return (
