	extends Omit<React.ComponentProps<"button">, "children" | "onClick"> {
	labels?: ContextfulSaveButtonLabels;
	onClick?: (
		event: React.MouseEvent<HTMLButtonElement>,
	) => void | Promise<void>;
}

const defaultLabels = {
	idle: "Save",
	loading: "Saving",
	success: "Saved",
	error: "Try again",
} satisfies Record<ContextfulSaveButtonStatus, string>;

function AnimatedChars({ text }: { text: string }) {
	return (
		<AnimatePresence mode="popLayout" initial={false}>
			{Array.from(text, (char, offset) => (
				<motion.span
					key={`${char}-${offset}`}
					layout
					initial={{ opacity: 0, scale: 0, filter: "blur(4px)" }}
					animate={{ opacity: 1, scale: 1, filter: "blur(0px)" }}
					exit={{ opacity: 0, scale: 0, filter: "blur(4px)" }}
					transition={{
						type: "spring",
						stiffness: 500,
						damping: 30,
						mass: 1,
					}}
					className="inline-block"
				>
					{char === " " ? "\u00A0" : char}
				</motion.span>
			))}
		</AnimatePresence>
	);
}

function ContextfulSaveButton({
	className,
	disabled,
	labels,
	onClick,
	...props
}: ContextfulSaveButtonProps) {
	const [status, setStatus] = useState<ContextfulSaveButtonStatus>("idle");
	const isRunning = useRef(false);
	const resetTimer = useRef<ReturnType<typeof setTimeout>>(undefined);
	const resolvedLabels = { ...defaultLabels, ...labels };
	const label = resolvedLabels[status];
	const isPending = status !== "idle";

	useEffect(
		() => () => {
			if (resetTimer.current) clearTimeout(resetTimer.current);
		},
		[],
	);

	async function handleClick(event: React.MouseEvent<HTMLButtonElement>) {
		if (isRunning.current) return;

		isRunning.current = true;
		setStatus("loading");

		try {
			await onClick?.(event);
			setStatus("success");
		} catch {
			setStatus("error");
		}

		resetTimer.current = setTimeout(() => {
			isRunning.current = false;
			setStatus("idle");
		}, FEEDBACK_DURATION);
	}

	return (
		<MotionConfig reducedMotion="user">
			<div className="relative inline-flex font-sans">
				<button
					data-slot="contextful-save-button"
					data-status={status}
					type="button"
					aria-busy={status === "loading"}
					disabled={disabled || isPending}
					onClick={handleClick}
					className={cn(
						"relative inline-flex h-12 min-w-36 select-none items-center justify-center rounded-full px-8 font-medium text-base outline-none duration-[160ms] ease-[cubic-bezier(0.23,1,0.32,1)] focus-visible:ring-3 focus-visible:ring-ring/50 active:not-disabled:scale-[0.97] motion-reduce:transform-none motion-reduce:transition-none",
						status === "idle" &&
							"bg-linear-to-b from-blue-400 to-blue-500 text-primary-foreground hover:from-blue-500 hover:to-blue-600 hover:shadow-sm",
						status !== "idle" &&
							"cursor-not-allowed bg-muted/60 text-muted-foreground",
						className,
					)}
					{...props}
				>
					<span className="flex items-center justify-center">
						<AnimatedChars text={label} />
					</span>
				</button>

				<AnimatePresence initial={false}>
					{status !== "idle" && (
						<motion.span
							initial={{ opacity: 0, scale: 0.94, x: -4 }}
							animate={{ opacity: 1, scale: 1, x: 0 }}
							exit={{ opacity: 0, scale: 0.94, x: -4 }}
							transition={{ duration: 0.18, ease: EASE_OUT }}
							aria-hidden="true"
							className={cn(
								"pointer-events-none absolute -top-1 -right-1 flex size-6 items-center justify-center overflow-hidden rounded-full",
								status === "loading" && "bg-muted text-muted-foreground",
								status === "success" && "bg-success text-white",
								status === "error" && "bg-destructive text-white",
							)}
						>
							<AnimatePresence initial={false} mode="wait">
								<motion.span
									key={status}
									initial={{ opacity: 0, scale: 0.94 }}
									animate={{ opacity: 1, scale: 1 }}
									exit={{ opacity: 0, scale: 0.94 }}
									transition={{ duration: 0.12, ease: EASE_OUT }}
									className="absolute inset-0 flex items-center justify-center [&_svg]:size-3.5"
								>
									{status === "loading" && (
										<LoaderCircleIcon className="animate-spin motion-reduce:animate-none" />
									)}
									{status === "success" && <CheckIcon />}
									{status === "error" && <XIcon />}
								</motion.span>
							</AnimatePresence>
						</motion.span>
					)}
				</AnimatePresence>

				<span className="sr-only" role="status" aria-live="polite">
					{status === "idle" ? "" : label}
				</span>
			</div>
		</MotionConfig>
	);
}

export {
	ContextfulSaveButton,
	type ContextfulSaveButtonLabels,
	type ContextfulSaveButtonProps,
	type ContextfulSaveButtonStatus,
};

export default ContextfulSaveButton;

src/registry/components/copy-button/copy:
"use client";

import { CheckIcon, CircleXIcon, CopyIcon } from "lucide-react";
import { motion } from "motion/react";
import type { ComponentProps } from "react";
import { Button } from "@/components/ui/button";
import type { CopyState } from "@/hooks/use-copy-to-clipboard";
import { useCopyToClipboard } from "@/hooks/use-copy-to-clipboard";
import { cn } from "@/lib/utils";
import {
	IconSwap,
	IconSwapItem,
} from "@/components/icon-swap/icon-swap";

export type CopyStateIconProps = {
	state: CopyState;
	/** Custom icon for idle state. */
	idleIcon?: React.ReactNode;
	/** Custom icon for done state. */
	doneIcon?: React.ReactNode;
	/** Custom icon for error state. */
	errorIcon?: React.ReactNode;
};

export function CopyStateIcon({
	state,
	idleIcon,
	doneIcon,
	errorIcon,
}: CopyStateIconProps) {
	let icon = idleIcon ?? (
		<CopyIcon data-icon="inline-start" data-slot="idle-icon" />
	);

	if (state === "done") {
		icon = doneIcon ?? (
			<CheckIcon data-icon="inline-start" data-slot="done-icon" />
		);
	} else if (state === "error") {
		icon = errorIcon ?? (
			<CircleXIcon data-icon="inline-start" data-slot="error-icon" />
		);
	}

	return (
		<IconSwap>
			<IconSwapItem key={state} as={motion.span}>
				{icon}
			</IconSwapItem>
		</IconSwap>
	);
}

export type CopyButtonProps = ComponentProps<typeof Button> & {
	/** The text to copy, or a function that returns the text. */
	text: string | (() => string);
	/** Called with the copied text on successful copy. */
	onCopySuccess?: (text: string) => void;
	/** Called with the error if the copy operation fails. */
	onCopyError?: (error: Error) => void;
} & Omit<CopyStateIconProps, "state">;

export function CopyButton({
	className,
	size = "icon",
	children,
	text,
	idleIcon,
	doneIcon,
	errorIcon,
	onClick,
	onCopySuccess,
	onCopyError,
	...props
}: CopyButtonProps) {
	const { state, copy } = useCopyToClipboard({
		onCopySuccess,
		onCopyError,
	});

	return (
		<Button
			className={cn("will-change-transform", className)}
			size={size}
			onClick={(e) => {
				void copy(text);
				onClick?.(e);
			}}
			aria-label="Copy"
			{...props}
		>
			<CopyStateIcon
				state={state}
				idleIcon={idleIcon}
				doneIcon={doneIcon}
				errorIcon={errorIcon}
			/>
			{children}
		</Button>
	);
}

export default CopyButton;

src/registry/components/email-dock/email:
"use client";

import { Link2, Mail, User } from "lucide-react";
import * as React from "react";

import { cn } from "@/lib/utils";

/** Which part of the email string to emphasize on dock hover / tap. */
type EmailHighlightSegment = "local" | "domain" | "full";

interface EmailHighlight {
	/** Email part to emphasize on hover. */
	segment: EmailHighlightSegment;
	/** Optional link (e.g. `mailto:` or website). */
	href?: string;
	/** Open `href` in a new tab. */
	external?: boolean;
	/** Accessible name for the dock control; derived from segment when omitted. */
	label?: string;
}

const SEGMENT_META: Record<
	EmailHighlightSegment,
	{
		icon: React.ComponentType<{ className?: string }>;
		label: string;
		badge: string;
	}
> = {
	local: { icon: User, label: "Highlight username", badge: "name" },
	domain: { icon: Link2, label: "Highlight domain", badge: "website" },
	full: { icon: Mail, label: "Highlight full email", badge: "email" },
};

const DEFAULT_HIGHLIGHTS: EmailHighlight[] = [
	{ segment: "local" },
	{ segment: "domain" },
	{ segment: "full" },
];

const HIGHLIGHT_CLASS =
	"bg-gradient-to-r from-blue-400 to-blue-500 bg-clip-text text-transparent";

function parseEmail(email: string) {
	const atIndex = email.indexOf("@");
	if (atIndex === -1) {
		return { local: email, at: "", domain: "" };
	}
	return {
		local: email.slice(0, atIndex),
		at: "@",
		domain: email.slice(atIndex + 1),
	};
}

function HighlightableText({
	text,
	active,
	activeLabel,
	showBadge = true,
}: {
	text: string;
	active: boolean;
	activeLabel: string;
	showBadge?: boolean;
}) {
	const showDecoration = active && showBadge;

	return (
		<span className="relative inline-block">
			<span
				aria-hidden
				className={cn(active ? HIGHLIGHT_CLASS : "text-inherit")}
			>
				{text}
			</span>

			{showDecoration ? (
				<>
					<span
						aria-hidden
						className="pointer-events-none absolute -inset-x-0.5 top-[99%] -bottom-2 -z-10 border-border border-r border-b border-l border-dotted"
					/>
					<span
						aria-hidden
						className="pointer-events-none absolute top-[calc(100%+0.6rem)] left-1/2 -translate-x-1/2 whitespace-nowrap font-thin text-[0.42em] text-foreground/35 tracking-[0.18em]"
					>
						{activeLabel}
					</span>
				</>
			) : null}
		</span>
	);
}

interface EmailDockProps extends React.ComponentProps<"div"> {
	/** Full email address shown in the card. */
	email: string;
	/** Dock icons and highlight rules. Defaults to username / domain / full. */
	highlights?: EmailHighlight[];
}

function EmailDock({
	email,
	highlights = DEFAULT_HIGHLIGHTS,
	className,
	...props
}: EmailDockProps) {
	const parsed = React.useMemo(() => parseEmail(email), [email]);
	const [activeSegment, setActiveSegment] =
		React.useState<EmailHighlightSegment | null>(null);

	const deactivate = () => setActiveSegment(null);

	return (
		<div
			data-slot="email-dock"
			className={cn(
				"relative flex w-full max-w-xl flex-col items-center justify-center",
				className,
			)}
			{...props}
		>
			<p
				data-slot="email-dock-address"
				className="w-full text-center font-medium text-[clamp(1.35rem,4.5vw,2.25rem)] text-foreground/35 leading-tight tracking-tight"
			>
				<span className="sr-only">{email}</span>
				<span className="relative inline-block">
					<HighlightableText
						text={parsed.local}
						active={activeSegment === "local" || activeSegment === "full"}
						activeLabel={SEGMENT_META.local.badge}
						showBadge={activeSegment === "local"}
					/>

					{parsed.at ? (
						<span
							aria-hidden
							className={cn(
								activeSegment === "full" ? HIGHLIGHT_CLASS : "text-inherit",
							)}
						>
							{parsed.at}
						</span>
					) : null}

					{parsed.domain ? (
						<HighlightableText
							text={parsed.domain}
							active={activeSegment === "domain" || activeSegment === "full"}
							activeLabel={SEGMENT_META.domain.badge}
							showBadge={activeSegment === "domain"}
						/>
					) : null}

					{activeSegment === "full" ? (
						<>
							<span
								aria-hidden
								className="pointer-events-none absolute -inset-x-0.5 top-[99%] -bottom-2 -z-10 border-border border-r border-b border-l border-dotted"
							/>
							<span
								aria-hidden
								className="pointer-events-none absolute top-[calc(100%+0.6rem)] left-1/2 -translate-x-1/2 whitespace-nowrap font-thin text-[0.42em] text-foreground/35 tracking-[0.18em]"
							>
								{SEGMENT_META.full.badge}
							</span>
						</>
					) : null}
				</span>
			</p>

			{highlights.length > 0 ? (
				<div
					data-slot="email-dock-toolbar"
					role="group"
					aria-label="Email actions"
					className="mt-8 flex items-center justify-center gap-5 sm:mt-10 sm:gap-6"
					onPointerLeave={deactivate}
					onBlur={(event) => {
						if (!event.currentTarget.contains(event.relatedTarget as Node)) {
							deactivate();
						}
					}}
				>
					{highlights.map((highlight, index) => (
						<DockAction
							key={`${highlight.segment}-${index}`}
							highlight={highlight}
							isActive={activeSegment === highlight.segment}
							onActivate={() => setActiveSegment(highlight.segment)}
						/>
					))}
				</div>
			) : null}
		</div>
	);
}

interface DockActionProps {
	highlight: EmailHighlight;
	isActive: boolean;
	onActivate: () => void;
}

function DockAction({ highlight, isActive, onActivate }: DockActionProps) {
	const meta = SEGMENT_META[highlight.segment];
	const Icon = meta.icon;
	const label = highlight.label ?? meta.label;
	const sharedClass = cn(
		"flex size-10 items-center justify-center rounded-full text-foreground/40",
		"hover:translate-y-[-2px] hover:text-foreground/80",
		"focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring/50",
		"sm:size-11",
		isActive && "text-foreground",
	);

	const handlers = {
		onPointerEnter: onActivate,
		onFocus: onActivate,
		onClick: (event: React.MouseEvent) => {
			if (highlight.href) return;
			event.preventDefault();
			onActivate();
		},
	};

	if (highlight.href) {
		return (
			<a
				data-slot="email-dock-action"
				href={highlight.href}
				aria-label={label}
				target={highlight.external ? "_blank" : undefined}
				rel={highlight.external ? "noopener noreferrer" : undefined}
				className={sharedClass}
				{...handlers}
			>
				<Icon className="size-[1.15rem] stroke-[1.5] sm:size-5" aria-hidden />
			</a>
		);
	}

	return (
		<button
			type="button"
			data-slot="email-dock-action"
			aria-label={label}
			className={sharedClass}
			{...handlers}
		>
			<Icon className="size-[1.15rem] stroke-[1.5] sm:size-5" aria-hidden />
		</button>
	);
}

export type { EmailDockProps, EmailHighlight, EmailHighlightSegment };
export { DEFAULT_HIGHLIGHTS, EmailDock };

export default EmailDock;

src/registry/components/glow-card/glow-c:
"use client";

import {
	motion,
	useMotionTemplate,
	useMotionValue,
	useReducedMotion,
	useSpring,
} from "motion/react";
import type { ComponentProps, PointerEvent } from "react";

import { cn } from "@/lib/utils";

export interface GlowCardProps extends ComponentProps<"div"> {
	glowColor?: string;
	glowSize?: number;
}

export function GlowCard({
	children,
	className,
	glowColor = "hsl(217 91% 60%)",
	glowSize = 140,
	onPointerLeave,
	onPointerMove,
	...props
}: GlowCardProps) {
	const mouseX = useMotionValue(-glowSize);
	const mouseY = useMotionValue(-glowSize);
	const smoothX = useSpring(mouseX, {
		stiffness: 220,
		damping: 30,
		mass: 0.25,
	});
	const smoothY = useSpring(mouseY, {
		stiffness: 220,
		damping: 30,
		mass: 0.25,
	});
	const reduceMotion = useReducedMotion();
	const backgroundImage = useMotionTemplate`radial-gradient(${glowSize}px circle at ${smoothX}px ${smoothY}px, ${glowColor}, transparent 70%)`;

	function handlePointerMove(event: PointerEvent<HTMLDivElement>) {
		onPointerMove?.(event);
		if (
			event.defaultPrevented ||
			event.pointerType === "touch" ||
			reduceMotion
		) {
			return;
		}

		const bounds = event.currentTarget.getBoundingClientRect();
		mouseX.set(event.clientX - bounds.left);
		mouseY.set(event.clientY - bounds.top);
	}

	function handlePointerLeave(event: PointerEvent<HTMLDivElement>) {
		onPointerLeave?.(event);
		mouseX.set(-glowSize);
		mouseY.set(-glowSize);
	}

	return (
		<div
			className={cn(
				"group/glow-card relative overflow-hidden rounded-xl bg-border/70 p-px",
				className,
			)}
			data-slot="glow-card"
			onPointerLeave={handlePointerLeave}
			onPointerMove={handlePointerMove}
			{...props}
		>
			<motion.div
				aria-hidden="true"
				className="pointer-events-none absolute inset-0 opacity-0 transition-opacity duration-200 ease-[cubic-bezier(0.23,1,0.32,1)] motion-reduce:opacity-0 motion-reduce:transition-none [@media(hover:hover)_and_(pointer:fine)]:group-hover/glow-card:opacity-100"
				style={{ backgroundImage }}
			/>
			<div className="relative h-full overflow-hidden rounded-[inherit]">
				{children}
			</div>
		</div>
	);
}

