						className="pointer-events-none absolute right-[0.9em] bottom-[0.55em] flex items-center gap-[0.35em]"
					>
						{["left", "right"].map((eye) => (
							<motion.span
								key={eye}
								className="relative size-[0.72em] overflow-hidden rounded-full bg-foreground"
								animate={
									reduceMotion === true || !isOpen
										? { transform: "scaleY(1)" }
